CREATE TABLE "RefreshToken" ("id" BIGSERIAL NOT NULL, "tokenHash" TEXT NOT NULL, "userSub" TEXT NOT NULL, "name" TEXT NOT NULL, "role" TEXT NOT NULL, "email" TEXT NOT NULL, "expiresAt" TIMESTAMP(3) NOT NULL, "revokedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "RefreshToken_pkey" PRIMARY KEY ("id")); CREATE UNIQUE INDEX "RefreshToken_tokenHash_key" ON "RefreshToken"("tokenHash"); CREATE INDEX "RefreshToken_userSub_expiresAt_idx" ON "RefreshToken"("userSub", "expiresAt");